export function getGeneratedArtSprite(id: string | undefined): Uint32Array | undefined {
  if (!id) return undefined;
  const rle = GENERATED_ART_SPRITE_RLE[id as GeneratedArtSpriteId];
  if (!rle) return undefined;
  const out = new Uint32Array(S * S);
  let cursor = 0;
  for (let i = 0; i < rle.length; i += 2) {
    const count = rle[i] | 0;
    const value = rle[i + 1] >>> 0;
    out.fill(value, cursor, cursor + count);
    cursor += count;
  }
  return cursor === out.length ? out : undefined;
}
